import{_ as d,C as r,o as a,c as i,E as n,a3 as s}from"./chunks/framework.BmC9Ob7H.js";const o="/versions/v0.13.0/screens/devices/arpeggiator.png",x=JSON.parse('{"title":"Arp","description":"","frontmatter":{"title":"Arp","pageClass":"device-doc"},"headers":[],"relativePath":"devices/arpeggiator.md","filePath":"devices/arpeggiator.md"}'),l={name:"devices/arpeggiator.md"};function h(g,t,c,p,y,b){const e=r("DeviceHeading");return a(),i("div",null,[n(e,{slug:"arpeggiator",title:"Arp"}),t[0]||(t[0]=s('<p>Arpeggiate held notes</p><p><img src="'+o+'" alt="Arp parameters" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Place <strong>Arp</strong> after a chord or held-note source to <strong>cycle through held pitches</strong> with configurable pattern, rate, and gate.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Requires clock (internal or external) when sync is enabled.</p></div><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Bypass</td><td>0 – 1</td><td>When on, the device is disabled and MIDI passes through unchanged.</td></tr><tr><td>Rate</td><td>0 – 6</td><td>Clock division for each step — how fast the pattern advances.</td></tr><tr><td>Gate</td><td>10 – 200</td><td>Note length as a percentage of the step (10–200%).</td></tr><tr><td>Chord</td><td>-2 – 2</td><td>Adds parallel notes above each held pitch (−2 to +2 diatonic steps).</td></tr><tr><td>Octave</td><td>-5 – 5</td><td>Shifts the arpeggio pitch range by octaves (−5 to +5).</td></tr><tr><td>Repeat</td><td>0 – 16</td><td>How many times the arpeggio pattern cycles (0 = until release).</td></tr><tr><td>Re-Trig</td><td>0 – 9</td><td>Restarts the arpeggio pattern on this clock division or on each new note.</td></tr><tr><td>Sync</td><td>0 – 1</td><td>When on, rate follows MIDI clock; when off, uses async milliseconds.</td></tr><tr><td>Style</td><td>0 – 17</td><td>Arpeggio order and articulation pattern across held notes.</td></tr><tr><td>Async Rate</td><td>50 – 1000</td><td>Step period in milliseconds when sync is off (50–1000 ms).</td></tr></tbody></table></div><h2 id="parameter-values" tabindex="-1">Parameter values <a class="header-anchor" href="#parameter-values" aria-label="Permalink to &quot;Parameter values&quot;">​</a></h2><h3 id="bypass" tabindex="-1">Bypass <a class="header-anchor" href="#bypass" aria-label="Permalink to &quot;Bypass&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Device is active and processes MIDI.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Device is bypassed; messages pass through unchanged.</td></tr></tbody></table><h3 id="rate" tabindex="-1">Rate <a class="header-anchor" href="#rate" aria-label="Permalink to &quot;Rate&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>1/1</td><td>One note per bar (quarter-note grid).</td></tr><tr><td style="text-align:right;">1</td><td>1/2</td><td>Half-note steps.</td></tr><tr><td style="text-align:right;">2</td><td>1/4</td><td>Quarter-note steps.</td></tr><tr><td style="text-align:right;">3</td><td>1/8</td><td>Eighth-note steps.</td></tr><tr><td style="text-align:right;">4</td><td>1/16</td><td>Sixteenth-note steps.</td></tr><tr><td style="text-align:right;">5</td><td>1/32</td><td>Thirty-second-note steps.</td></tr><tr><td style="text-align:right;">6</td><td>1/64</td><td>Sixty-fourth-note steps.</td></tr></tbody></table><h3 id="re-trig" tabindex="-1">Re-Trig <a class="header-anchor" href="#re-trig" aria-label="Permalink to &quot;Re-Trig&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Pattern runs once per held chord.</td></tr><tr><td style="text-align:right;">1</td><td>Note</td><td>Restart pattern on every new note.</td></tr><tr><td style="text-align:right;">2</td><td>8 bars</td><td>Restart every 8 bars.</td></tr><tr><td style="text-align:right;">3</td><td>4 bars</td><td>Restart every 4 bars.</td></tr><tr><td style="text-align:right;">4</td><td>2 bars</td><td>Restart every 2 bars.</td></tr><tr><td style="text-align:right;">5</td><td>1 bar</td><td>Restart every bar.</td></tr><tr><td style="text-align:right;">6</td><td>1/2</td><td>Restart every half note.</td></tr><tr><td style="text-align:right;">7</td><td>1/4</td><td>Restart every quarter note.</td></tr><tr><td style="text-align:right;">8</td><td>1/8</td><td>Restart every eighth note.</td></tr><tr><td style="text-align:right;">9</td><td>1/16</td><td>Restart every sixteenth note.</td></tr></tbody></table><h3 id="sync" tabindex="-1">Sync <a class="header-anchor" href="#sync" aria-label="Permalink to &quot;Sync&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Free</td><td>Use async time (ms) instead of clock divisions.</td></tr><tr><td style="text-align:right;">1</td><td>Synced</td><td>Step rate follows MIDI clock divisions.</td></tr></tbody></table><h3 id="style" tabindex="-1">Style <a class="header-anchor" href="#style" aria-label="Permalink to &quot;Style&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Up</td><td>Lowest to highest note, repeating.</td></tr><tr><td style="text-align:right;">1</td><td>Down</td><td>Highest to lowest note, repeating.</td></tr><tr><td style="text-align:right;">2</td><td>Up-Down</td><td>Ascend then descend without repeating endpoints.</td></tr><tr><td style="text-align:right;">3</td><td>Down-Up</td><td>Descend then ascend without repeating endpoints.</td></tr><tr><td style="text-align:right;">4</td><td>Up &amp; Down</td><td>Ascend and descend, repeating top and bottom.</td></tr><tr><td style="text-align:right;">5</td><td>Down &amp; Up</td><td>Descend and ascend, repeating top and bottom.</td></tr><tr><td style="text-align:right;">6</td><td>Converge</td><td>Outside notes move inward.</td></tr><tr><td style="text-align:right;">7</td><td>Diverge</td><td>Inside notes move outward.</td></tr><tr><td style="text-align:right;">8</td><td>Conv-Div</td><td>Converge then diverge.</td></tr><tr><td style="text-align:right;">9</td><td>Pinky Up</td><td>Start from lowest, pinky-finger pattern up.</td></tr><tr><td style="text-align:right;">10</td><td>Pinky Up-Down</td><td>Pinky up pattern with return.</td></tr><tr><td style="text-align:right;">11</td><td>Thumb Up</td><td>Start from highest, thumb-finger pattern down.</td></tr><tr><td style="text-align:right;">12</td><td>Thumb Up-Down</td><td>Thumb up pattern with return.</td></tr><tr><td style="text-align:right;">13</td><td>Order</td><td>Order notes were played.</td></tr><tr><td style="text-align:right;">14</td><td>Velocity Up</td><td>Sort by velocity, ascending.</td></tr><tr><td style="text-align:right;">15</td><td>Velocity Down</td><td>Sort by velocity, descending.</td></tr><tr><td style="text-align:right;">16</td><td>Chord Trigger</td><td>All notes together each step.</td></tr><tr><td style="text-align:right;">17</td><td>Random</td><td>Random order each cycle.</td></tr></tbody></table>',18))])}const m=d(l,[["render",h]]);export{x as __pageData,m as default};
